public List preorderTraversal(TreeNode root) {
    List result = new ArrayList<>();
    preorder(root, result);
    return result;
}

private void preorder(TreeNode root, List result) {
    if (root == null) return;

    result.add(root.val);        // Visit root
    preorder(root.left, result); // Visit left subtree
    preorder(root.right, result); // Visit right subtree
}

// Iterative using Stack
public List preorderTraversalIterative(TreeNode root) {
    List result = new ArrayList<>();
    if (root == null) return result;

    Stack stack = new Stack<>();
    stack.push(root);

    while (!stack.isEmpty()) {
        TreeNode node = stack.pop();
        result.add(node.val);

        // Push right first, then left (so left is processed first)
        if (node.right != null) {
            stack.push(node.right);
        }
        if (node.left != null) {
            stack.push(node.left);
        }
    }

    return result;
}

